Write an equivalent for the following in Lua:
def elaborate_histogram(test):
    count = {}
    for char in test:
        if char != ' ':
            if char.lower() in count:
                count[char.lower()] += 1
            else:
                count[char.lower()] = 1

    max_count = max(count.values(), default=0)
    return {char: count_ for char, count_ in count.items() if count_ == max_count}

# Test cases:
print(elaborate_histogram('A B c 1 @'))  # should return {'a': 1, 'b': 1, 'c': 1, '1': 1, '@': 1}
print(elaborate_histogram('a B b A 4'))  # should return {'a': 2, 'b': 2}
print(elaborate_histogram('A b C a B 1 2 2'))  # should return {'a': 2, 'b': 2, '2': 2}
print(elaborate_histogram('B B B b A ! ! ! !'))  # should return {'b': 4, '!': 4}
print(elaborate_histogram(''))  # should return {}

